import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.BYehg5q7.js";const h=JSON.parse('{"title":"Specialty Labs","description":"","frontmatter":{},"headers":[],"relativePath":"guide/specialty-labs.md","filePath":"guide/specialty-labs.md","lastUpdated":1772873466000}'),i={name:"guide/specialty-labs.md"};function s(d,t,n,l,p,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="specialty-labs" tabindex="-1">Specialty Labs <a class="header-anchor" href="#specialty-labs" aria-label="Permalink to &quot;Specialty Labs&quot;">​</a></h1><p>Beyond standard blood work, getbased supports specialty lab tests. Two test types have dedicated support with built-in marker definitions; any other lab report goes through the generic custom marker pipeline where the AI extracts everything from your PDF.</p><h2 id="supported-test-types" tabindex="-1">Supported Test Types <a class="header-anchor" href="#supported-test-types" aria-label="Permalink to &quot;Supported Test Types&quot;">​</a></h2><h3 id="dedicated-support" tabindex="-1">Dedicated support <a class="header-anchor" href="#dedicated-support" aria-label="Permalink to &quot;Dedicated support&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Test Type</th><th>Examples</th><th>Built-in Markers</th></tr></thead><tbody><tr><td><strong>Metabolomix+</strong></td><td>Genova Metabolomix+ combo profiles</td><td>165 markers across 10 categories</td></tr><tr><td><strong>Fatty Acids</strong></td><td>Spadia, ZinZino BalanceTest, OmegaQuant</td><td>29 reference markers</td></tr></tbody></table><h3 id="generic-support-custom-marker-pipeline" tabindex="-1">Generic support (custom marker pipeline) <a class="header-anchor" href="#generic-support-custom-marker-pipeline" aria-label="Permalink to &quot;Generic support (custom marker pipeline)&quot;">​</a></h3><p>Any other specialty lab report can be imported — the AI extracts marker names, units, and reference ranges directly from your PDF. No built-in definitions needed.</p><p>Examples: DUTCH hormone panels, Hair Tissue Mineral Analysis (HTMA), GI-MAP, standalone OAT, and any other lab report.</p><h2 id="fatty-acid-labs" tabindex="-1">Fatty Acid Labs <a class="header-anchor" href="#fatty-acid-labs" aria-label="Permalink to &quot;Fatty Acid Labs&quot;">​</a></h2><p>Fatty acid tests are grouped by the product or lab that produced them. Each lab appears as its own subcategory under a <strong>Fatty Acids</strong> sidebar group, so results from different labs are never mixed together.</p><p><strong>Auto-detected labs:</strong></p><table tabindex="0"><thead><tr><th>Lab / Product</th><th>Detection</th></tr></thead><tbody><tr><td><strong>Spadia</strong></td><td>PDF content or filename</td></tr><tr><td><strong>ZinZino</strong> (BalanceTest)</td><td>PDF content or filename</td></tr><tr><td><strong>OmegaQuant</strong> (Basic/Plus/Complete, Ayumetrix)</td><td>PDF content or filename</td></tr></tbody></table><p>Other fatty acid labs are also supported — the AI identifies the lab name from the report and creates a product-specific category automatically.</p><div class="tip custom-block"><p class="custom-block-title">Comparing across labs</p><p>Even though results from different fatty acid labs appear in separate subcategories, the AI chat can compare and interpret results across all your fatty acid tests in a single conversation.</p></div><h2 id="metabolomix" tabindex="-1">Metabolomix+ <a class="header-anchor" href="#metabolomix" aria-label="Permalink to &quot;Metabolomix+&quot;">​</a></h2><p>Genova Metabolomix+ imports create multiple subcategories under an <strong>OAT</strong> sidebar group:</p><table tabindex="0"><thead><tr><th>Category</th><th>Markers</th><th>Examples</th></tr></thead><tbody><tr><td>Microbial Overgrowth</td><td>14</td><td>Citramalic acid, HPHPA, arabinose</td></tr><tr><td>Metabolic</td><td>22</td><td>Lactic, pyruvic, succinic, citric acid</td></tr><tr><td>Neurotransmitters</td><td>14</td><td>HVA, VMA, quinolinic acid</td></tr><tr><td>Nutritional &amp; Detox</td><td>24</td><td>Methylmalonic, glutathione markers</td></tr><tr><td>Amino Acids &amp; Lipids</td><td>18</td><td>Urine amino acids, fatty acid metabolites</td></tr><tr><td>Urine Amino Acids</td><td>21</td><td>Arginine, taurine, glycine</td></tr><tr><td>Urine Amino Metabolites</td><td>18</td><td>Methylhistidine, sarcosine</td></tr><tr><td>Toxic Elements</td><td>18</td><td>Lead, mercury, arsenic, cadmium</td></tr><tr><td>Nutrient Elements</td><td>14</td><td>Selenium, zinc, calcium, magnesium</td></tr><tr><td>Oxidative Stress</td><td>2</td><td>Lipid peroxides, 8-OHdG</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Drop your PDF</strong> on the dashboard — same as any other import</li><li><strong>AI detects the test type</strong> — the AI reads the report and identifies whether it&#39;s blood work, OAT, DUTCH, or another type</li><li><strong>Markers are mapped</strong> with test-type-prefixed categories (e.g., <code>oatNutritional</code>, <code>dutchHormones</code>) to keep specialty results separate from standard blood markers</li><li><strong>Reference ranges come from your PDF</strong> — the AI extracts the lab&#39;s stated ranges rather than using built-in defaults</li><li><strong>Review and confirm</strong> in the import preview, then your results appear in charts</li></ol><div class="tip custom-block"><p class="custom-block-title">Your lab&#39;s reference ranges</p><p>Unlike standard blood markers that use built-in reference ranges, specialty markers use the ranges printed on your specific lab report. This means your charts reflect the ranges your lab considers normal.</p></div><h2 id="custom-marker-pipeline" tabindex="-1">Custom Marker Pipeline <a class="header-anchor" href="#custom-marker-pipeline" aria-label="Permalink to &quot;Custom Marker Pipeline&quot;">​</a></h2><p>Specialty markers flow through the <a href="./custom-markers.html">custom marker</a> pipeline. For each marker the AI extracts:</p><ul><li>A <strong>key</strong> with a test-type-prefixed category (e.g., <code>oatMicrobial.someMarker</code>)</li><li>A <strong>name</strong> in plain English</li><li>The <strong>unit</strong> of measurement</li><li><strong>Reference ranges</strong> from the lab report</li><li>A <strong>group</strong> tag (e.g., &quot;OAT&quot;, &quot;DUTCH&quot;) for sidebar organization</li></ul><p>These are created automatically during import — no manual setup required.</p><h2 id="sidebar-grouping" tabindex="-1">Sidebar Grouping <a class="header-anchor" href="#sidebar-grouping" aria-label="Permalink to &quot;Sidebar Grouping&quot;">​</a></h2><p>Specialty categories appear under collapsible group headers in the sidebar. For example, an OAT import creates categories like &quot;Microbial Overgrowth&quot;, &quot;Nutritional Markers&quot;, and &quot;Oxalate Markers&quot; — all grouped under an <strong>OAT</strong> header you can expand or collapse.</p><p>Click the group header to toggle visibility. Collapse state is remembered across sessions.</p><h2 id="importing-multiple-specialty-tests" tabindex="-1">Importing Multiple Specialty Tests <a class="header-anchor" href="#importing-multiple-specialty-tests" aria-label="Permalink to &quot;Importing Multiple Specialty Tests&quot;">​</a></h2><p>If you import multiple reports of the same test type over time, the markers are matched to existing custom marker definitions. This gives you trend tracking across specialty labs just like standard blood work.</p><p>For fatty acid tests, each lab stays in its own subcategory — importing a ZinZino report won&#39;t merge with your Spadia results. Re-importing a PDF updates the category labels if they were incorrect from a previous import.</p><div class="warning custom-block"><p class="custom-block-title">Model consistency</p><p>Use the same AI model for all imports of a given test type. Different models may generate different marker keys for the same test, which prevents proper trend tracking. See <a href="./ai-providers.html#model-consistency">AI Providers</a> for details.</p></div>',31)])])}const m=e(i,[["render",s]]);export{h as __pageData,m as default};
